import React, { useState } from "react";
import axios from "axios";
import "./CarBooking.css";

const API = "http://localhost:5000/api";

export default function CarBooking() {
  const [view, setView] = useState("booking");
  const [selectedCar, setSelectedCar] = useState(null);
  const [bookings, setBookings] = useState([]);

  const [pickup, setPickup] = useState("");
  const [drop, setDrop] = useState("");
  const [pickupDate, setPickupDate] = useState("");
  const [dropDate, setDropDate] = useState("");
  const [pickupTime, setPickupTime] = useState("");
  const [dropTime, setDropTime] = useState("");

  const [amount, setAmount] = useState(0);
  const [paymentMethod, setPaymentMethod] = useState("");

  const [otpSent, setOtpSent] = useState(false);
  const [serverOtp, setServerOtp] = useState("");
  const [enteredOtp, setEnteredOtp] = useState("");
  const [otpVerified, setOtpVerified] = useState(false);

  const cars = [
      {
      id: 1,
      name: "Swift Dzire",
      image: "data:image/jpeg;base64,",
      price: 200,
      rating: 4.5,
      
    },
    {
      id: 2,
      name: "Innova Crysta",
      image: "https://stimg.cardekho.com/images/carexteriorimages/930x620/Toyota/Innova-Crysta/9608/1755846139274/front-left-side-47.jpg",
      price: 500,
      rating: 4.8,
    },
    {
      id: 3,
      name: "Hyundai i20",
      image: "data:image/jpeg;base64,",
      price: 250,
      rating: 4.3,
    },
    {
      id: 4,
      name: "BMW",
      image: "data:image/jpeg;base64,",
      price: 1000,
      rating: 4.3,
    },
    {
      id: 6,
      name: "Audi",
      image: "https://imgd.aeplcdn.com/664x374/n/cw/ec/124141/a8-l-exterior-right-front-three-quarter-3.jpeg?isig=0&q=80",
      price: 1500,
      rating: 4.3,
    },
    {
      id: 7,
      name: "Rolls Royce",
      image: "data:image/jpeg;base64,",
      price: 2000,
      rating: 4.3,
    },
    {
      id: 8,
      name: "TATA Tigo",
      image: "data:image/jpeg;base64,",
      price: 250,
      rating: 4.3,
    },
    {
      id: 9,
      name: "2025 Maruti Suzuki Baleno",
      image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcThoZUcEhI_2nVcydS2K2F9S2ssau-t3pYwLMR9jN3b4-Yhfv387hhYXxiTOwdNvKdOMLpKsKbrvUEXnclrDZVMQPOOTC6bVKTwrX6OfqPn&s=10",
      price: 250,
      rating: 4.3,
    },
    
];

  const calculateAmount = () => {
    if (!pickupDate || !dropDate || !pickupTime || !dropTime || !selectedCar) return;

    const start = new Date(`${pickupDate}T${pickupTime}`);
    const end = new Date(`${dropDate}T${dropTime}`);
    const hours = Math.ceil((end - start) / (1000 * 60 * 60));

    if (hours <= 0) return alert("Invalid time selection");

    setAmount(hours * selectedCar.price);
  };

  const sendOtp = async () => {
    if (!paymentMethod) return alert("Select payment method");
    calculateAmount();

    const res = await axios.post(`${API}/otp/send`, { mobile: "9999999999" });
    setServerOtp(res.data.otp);
    setOtpSent(true);
    alert(`OTP (demo): ${res.data.otp}`);
  };

  const verifyOtp = () => {
    if (enteredOtp === serverOtp) {
      setOtpVerified(true);
      alert("OTP Verified ");
    } else {
      alert("Invalid OTP ");
    }
  };

  const bookNow = async () => {
    const token = localStorage.getItem("token");

    const res = await axios.post(
      `${API}/bookings/create`,
      {
        car: selectedCar.name,
        pickup,
        drop,
        pickupDate,
        dropDate,
        pickupTime,
        dropTime,
        amount,
        paymentMethod,
      },
      {
        headers: { Authorization: `Bearer ${token}` },
      }
    );

    setBookings([...bookings, res.data]);
    alert("Booking Successful 🚗");
    resetAll();
  };

  const resetAll = () => {
    setSelectedCar(null);
    setPickup("");
    setDrop("");
    setPickupDate("");
    setDropDate("");
    setPickupTime("");
    setDropTime("");
    setAmount(0);
    setPaymentMethod("");
    setOtpSent(false);
    setEnteredOtp("");
    setOtpVerified(false);
  };

  return (
    <div className="car-booking-container">
      <div className="top-bar">
        <button onClick={() => setView("booking")}>🚗 Book Car</button>
        <button onClick={() => setView("my")}>📋 My Bookings</button>
      </div>

      {view === "booking" && (
        <>
          <h2>Select Car</h2>
          <div className="car-list">
            {cars.map((car) => (
              <div key={car.id} className={`car-card ${selectedCar?.id === car.id ? "selected" : ""}`} onClick={() => setSelectedCar(car)}>
                <img src={car.image} alt={car.name} />
                <h3>{car.name}</h3>
                <p>₹{car.price}/hour</p>
              </div>
            ))}
          </div>

          {selectedCar && (
            <div className="booking-form">
              <input placeholder="Pickup" value={pickup} onChange={(e) => setPickup(e.target.value)} />
              <input placeholder="Drop" value={drop} onChange={(e) => setDrop(e.target.value)} />

              <input type="date" value={pickupDate} onChange={(e) => setPickupDate(e.target.value)} />
              <input type="time" value={pickupTime} onChange={(e) => setPickupTime(e.target.value)} />

              <input type="date" value={dropDate} onChange={(e) => setDropDate(e.target.value)} />
              <input type="time" value={dropTime} onChange={(e) => setDropTime(e.target.value)} />

              <p>Total Amount: ₹{amount}</p>

              <div className="payment-box">
                <label><input type="radio" value="cash" checked={paymentMethod === "cash"} onChange={(e) => setPaymentMethod(e.target.value)} /> Cash</label>
                <label><input type="radio" value="card" checked={paymentMethod === "card"} onChange={(e) => setPaymentMethod(e.target.value)} /> Card</label>
              </div>

              {!otpSent && <button onClick={sendOtp}>Send OTP</button>}

              {otpSent && !otpVerified && (
                <>
                  <input placeholder="Enter OTP" value={enteredOtp} onChange={(e) => setEnteredOtp(e.target.value)} />
                  <button onClick={verifyOtp}>Verify OTP</button>
                </>
              )}

              {otpVerified && <button onClick={bookNow}>Confirm Booking</button>}
            </div>
          )}
        </>
      )}

      {view === "my" && bookings.map((b, i) => (
        <div key={i} className="booking-card">
          <h4>{b.car}</h4>
          <p>{b.pickup} ➝ {b.drop}</p>
          <p>₹{b.amount} ({b.paymentMethod})</p>
        </div>
      ))}
    </div>
  );
}
